variantConfig.listHandler:
async (config) => {
  const res = await integration.fetch('/sites?search=*&$select=id,displayName,name&$top=50')
  const data = await res.json()
  if (!Array.isArray(data?.value)) return []
  return data.value
    .map(site => ({ id: site.id, name: site.displayName || site.name || site.id }))
    .filter(s => s.id && s.name)
}

async (config) => {
  if (!config.siteId) return []
  const res = await integration.fetch(`/sites/${encodeURIComponent(config.siteId)}/drives?$select=id,name,driveType,system`)
  const data = await res.json()
  if (!Array.isArray(data?.value)) return []
  return data.value
    .filter(d => !d.system)
    .map(d => ({ id: d.id, name: d.name || d.id }))
    .filter(d => d.id && d.name)
}

async (config) => {
  if (!config.driveId) return []
  const res = await integration.fetch(`/drives/${encodeURIComponent(config.driveId)}/root/children?$select=id,name,folder&$top=100`)
  const data = await res.json()
  if (!Array.isArray(data?.value)) return []
  return data.value
    .filter(item => item.folder)
    .map(item => ({ id: item.id, name: item.name || item.id }))
    .filter(item => item.id && item.name)
}
